// ═══════════════════════════════════════════
// PREPARE STANDUP MESSAGES + READ HISTORY
// One item per team member
// ═══════════════════════════════════════════

const config = $input.first().json;
const chatIds = config.team_chat_ids.split(',').map(s => s.trim()).filter(Boolean);
const names = config.team_names.split(',').map(s => s.trim()).filter(Boolean);

const today = new Date();
const standupId = 'standup_' + today.toISOString().substring(0, 10).replace(/-/g, '');
const standupDate = today.toISOString();
const dateStr = today.toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
});

const message = [
  `📋 <b>Weekly Standup — ${dateStr}</b>\n`,
  `Hi! Please reply to this message with your update:\n`,
  `<b>1.</b> ${config.question_1}`,
  `<b>2.</b> ${config.question_2}`,
  `<b>3.</b> ${config.question_3}\n`,
  `Reply directly in this chat. Have a great week! 💪`,
].join('\n');

return chatIds.map((id, i) => ({
  json: {
    standup_id: standupId,
    standup_date: standupDate,
    chat_id: id,
    name: names[i] || `Member ${i + 1}`,
    message: message,
  }
}));

// ═══════════════════════════════════════════
// FETCH RECENT MESSAGES FROM TELEGRAM
// Uses getUpdates to find replies sent
// during the wait period
// ═══════════════════════════════════════════

const config = $('⚙️ Settings').first().json;
const chatIds = config.team_chat_ids.split(',').map(s => s.trim());
const names = config.team_names.split(',').map(s => s.trim());

const prepared = $('📝 Prepare Messages').all();
const standupId = prepared[0]?.json?.standup_id || 'unknown';
const standupDate = prepared[0]?.json?.standup_date || new Date().toISOString();
const standupTime = new Date(standupDate);

let botToken = '';
try {
  botToken = config.telegram_bot_token || '';
} catch (e) {}

if (!botToken) {
  return [{ json: {
    standup_id: standupId,
    standup_date: standupDate,
    responses: [],
    missing: names,
    total_team: chatIds.length,
    response_count: 0,
    note: 'Add telegram_bot_token to Settings to auto-collect responses, or just send the AI summary based on what is in the chat manually.',
  } }];
}

try {
  const r = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.telegram.org/bot${botToken}/getUpdates`,
    qs: { limit: 100, timeout: 0 },
    timeout: 10000,
  });

  const updates = r.result || [];
  const responses = [];
  const responded = new Set();

  for (let i = updates.length - 1; i >= 0; i--) {
    const u = updates[i];
    const msg = u.message;
    if (!msg || !msg.text) continue;

    const fromId = String(msg.from?.id || '');
    const idx = chatIds.indexOf(fromId);
    if (idx === -1 || responded.has(fromId)) continue;

    const msgDate = new Date((msg.date || 0) * 1000);
    if (msgDate < standupTime) continue;

    if (msg.text.startsWith('/')) continue;
    if (msg.text.includes('Weekly Standup') && msg.text.includes('Reply directly')) continue;

    responded.add(fromId);
    responses.push({
      name: names[idx] || `Member ${idx + 1}`,
      response: msg.text,
      responded_at: msgDate.toISOString(),
    });
  }

  const missing = chatIds
    .map((id, i) => ({ id, name: names[i] || id }))
    .filter(m => !responded.has(m.id))
    .map(m => m.name);

  return [{ json: {
    standup_id: standupId,
    standup_date: standupDate,
    responses: responses,
    missing: missing,
    total_team: chatIds.length,
    response_count: responses.length,
  } }];

} catch (err) {
  return [{ json: {
    standup_id: standupId,
    standup_date: standupDate,
    responses: [],
    missing: names,
    total_team: chatIds.length,
    response_count: 0,
    error: err.message,
  } }];
}

// ═══════════════════════════════════════════
// AI SUMMARIZE STANDUP via Groq
// Smart retry on rate limit
// ═══════════════════════════════════════════

const config = $('⚙️ Settings').first().json;
const data = $input.first().json;
const responses = data.responses || [];
const missing = data.missing || [];

let aiSummary = '';
let retriesUsed = 0;

if (responses.length === 0) {
  aiSummary = `⚠️ No responses collected this week.\n\nMissing: ${missing.join(', ')}\n\nNote: ${data.note || 'Team members may not have replied yet.'}`;
} else {
  let context = '';
  for (const r of responses) {
    context += `\n${r.name}:\n${r.response}\n`;
  }

  const prompt = `You are a team standup summarizer. Below are individual standup updates from ${responses.length} team members. Create a concise executive summary in this exact format:\n\n📌 KEY ACCOMPLISHMENTS LAST WEEK\n- [bullet point 1]\n- [bullet point 2]\n- [bullet point 3]\n\n🎯 THIS WEEK'S PLAN\n- [bullet point 1]\n- [bullet point 2]\n- [bullet point 3]\n\n🚧 BLOCKERS & RISKS\n- [list any blockers, or write \"None reported\"]\n\n💪 TEAM HEALTH\n[One sentence assessment: on track / needs attention / at risk]\n\nIndividual updates:\n${context}`;

  const maxRetries = 2;
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const r = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.groq.com/openai/v1/chat/completions',
        headers: {
          'Authorization': 'Bearer ' + config.groq_api_key,
          'Content-Type': 'application/json',
        },
        body: {
          model: 'llama-3.1-8b-instant',
          messages: [{ role: 'user', content: prompt }],
          temperature: 0.3,
          max_tokens: 800,
        },
        timeout: 30000,
      });
      aiSummary = r.choices?.[0]?.message?.content || 'AI summary generation failed.';
      break;
    } catch (err) {
      retriesUsed = attempt + 1;
      const is429 = (err.message || '').includes('429');
      if (is429 && attempt < maxRetries) {
        await new Promise(r => setTimeout(r, 5000));
        continue;
      }
      aiSummary = `⚠️ AI summary unavailable.\n\nRaw responses:\n${context}`;
      break;
    }
  }
}

const dateStr = new Date(data.standup_date).toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
});

let finalMessage = `📋 <b>Weekly Standup Summary</b>\n`;
finalMessage += `📅 ${dateStr}\n`;
finalMessage += `👥 Responded: ${responses.length}/${data.total_team}\n`;
if (missing.length > 0 && responses.length > 0) {
  finalMessage += `⚠️ Missing: ${missing.join(', ')}\n`;
}
finalMessage += `\n${aiSummary}`;

return [{ json: {
  ...data,
  ai_summary: aiSummary,
  final_message: finalMessage,
  team_lead_chat_id: config.team_lead_chat_id,
} }];
